#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *cnt = (int*)calloc(N+2,sizeof(int));
        int cur=0, mx=0;
        for(int i=0;i<N;i++){
            int x; scanf("%d",&x);
            cnt[x]++;
            if(cnt[x]&1) cur++; else cur--;
            if(cur>mx) mx=cur;
        }
        printf("%d\n",mx);
        free(cnt);
    }
    return 0;
}

