import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        freq = [0] * (N + 2)
        cur = mx = 0
        for _ in range(N):
            x = next(it)
            freq[x] += 1
            if freq[x] & 1:
                cur += 1
            else:
                cur -= 1
            if cur > mx:
                mx = cur
        out_lines.append(str(mx))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

